import ldap

def search_user_by_username(ldap_url, base_dn, username):
    # Initialize the LDAP connection
    ldap_conn = ldap.initialize(ldap_url)
    
    # Set up the filter for searching by username
    search_filter = f"(uid={username})"
    
    # Perform the search operation
    result_id = ldap_conn.search(base_dn, ldap.SCOPE_SUBTREE, search_filter)
    
    # Get the results
    result_set = []
    while 1:
        result_type, result_data = ldap_conn.result(result_id, 0)
        if not result_data:
            break
        else:
            if result_type == ldap.RES_SEARCH_ENTRY:
                result_set.append(result_data)
    
    # Close the connection
    ldap_conn.unbind_s()
    
    return result_set

